"python3 -c \"\nimport json, re\nlongest_block = ''\nwith open('/Users/rohan/.gemini/antigravity-ide/brain/7760f898-6df2-4143-a541-ee055682e01e/.system_generated/logs/transcript.jsonl', 'r') as f:\n    for line in f:\n        # Find all strings or values that contain def _modal_daily_menu\n        for match in re.finditer(r'def _modal_daily_menu', line):\n            # Let's extract the enclosing JSON string or block\n            # For simplicity, search for occurrences in the raw line\n            pass\n        # Let's try to load JSON and recursively look for strings containing 'def _modal_daily_menu'\n        try:\n            data = json.loads(line)\n            def find_strings(obj):\n                global longest_block\n                if isinstance(obj, str):\n                    if 'def _modal_daily_menu' in obj:\n                        if len(obj) > len(longest_block):\n                            longest_block = obj\n                elif isinstance(obj, dict):\n                    for v in obj.values():\n                        find_strings(v)\n                elif isinstance(obj, list):\n                    for v in obj:\n                        find_strings(v)\n            find_strings(data)\n        except Exception:\n            pass\n\nprint('Longest block found has length:', len(longest_block))\nwith open('longest_recovered.py', 'w') as out:\n    out.write(longest_block)\n\""